package com.example.enterprise.service;

import com.example.enterprise.domain.User;
import com.example.enterprise.repository.UserRepository;
import jakarta.persistence.EntityNotFoundException;
import java.util.List;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class UserService {

    private final UserRepository userRepository;

    public UserService(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Transactional
    public User createUser(User user) {
        if (userRepository.existsByUsername(user.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (userRepository.existsByEmail(user.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }
        return userRepository.save(user);
    }

    @Transactional(readOnly = true)
    public User getUser(Long id) {
        return userRepository.findById(id)
                .orElseThrow(() -> new EntityNotFoundException("User not found: " + id));
    }

    @Transactional(readOnly = true)
    public User getUserByUsername(String username) {
        return userRepository.findByUsername(username)
                .orElseThrow(() -> new EntityNotFoundException("User not found: " + username));
    }

    @Transactional(readOnly = true)
    public List<User> getAllUsers() {
        return userRepository.findAll();
    }

    @Transactional
    public User updateUser(Long id, User updated) {
        User existing = getUser(id);
        if (!existing.getUsername().equals(updated.getUsername()) && userRepository.existsByUsername(updated.getUsername())) {
            throw new IllegalArgumentException("Username already exists");
        }
        if (!existing.getEmail().equals(updated.getEmail()) && userRepository.existsByEmail(updated.getEmail())) {
            throw new IllegalArgumentException("Email already exists");
        }
        existing.setUsername(updated.getUsername());
        existing.setEmail(updated.getEmail());
        existing.setPasswordHash(updated.getPasswordHash());
        existing.setActive(updated.isActive());
        return userRepository.save(existing);
    }

    @Transactional
    public void deleteUser(Long id) {
        if (!userRepository.existsById(id)) {
            throw new EntityNotFoundException("User not found: " + id);
        }
        userRepository.deleteById(id);
    }
}

package com.example.enterprise.service;

import com.example.enterprise.domain.TransactionRecord;
import com.example.enterprise.domain.TransactionStatus;
import com.example.enterprise.domain.TransactionType;
import com.example.enterprise.domain.User;
import com.example.enterprise.repository.TransactionRepository;
import com.example.enterprise.repository.UserRepository;
import jakarta.persistence.EntityNotFoundException;
import java.math.BigDecimal;
import java.util.List;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;

@Service
public class TransactionService {

    private final TransactionRepository transactionRepository;
    private final UserRepository userRepository;

    public TransactionService(TransactionRepository transactionRepository, UserRepository userRepository) {
        this.transactionRepository = transactionRepository;
        this.userRepository = userRepository;
    }

    @Transactional
    public TransactionRecord createTransaction(Long userId, BigDecimal amount, TransactionType type, String description) {
        User user = userRepository.findById(userId)
                .orElseThrow(() -> new EntityNotFoundException("User not found: " + userId));

        TransactionRecord record = new TransactionRecord(user, amount, type, TransactionStatus.PENDING, description);
        TransactionRecord saved = transactionRepository.save(record);
        saved.setStatus(TransactionStatus.COMPLETED);
        return transactionRepository.save(saved);
    }

    @Transactional(readOnly = true)
    public TransactionRecord getTransaction(Long id) {
        return transactionRepository.findById(id)
                .orElseThrow(() -> new EntityNotFoundException("Transaction not found: " + id));
    }

    @Transactional(readOnly = true)
    public List<TransactionRecord> getTransactionsByUser(Long userId) {
        return transactionRepository.findByUserId(userId);
    }

    @Transactional(readOnly = true)
    public List<TransactionRecord> getTransactionsByStatus(TransactionStatus status) {
        return transactionRepository.findByStatus(status);
    }

    @Transactional
    public TransactionRecord updateStatus(Long transactionId, TransactionStatus status) {
        TransactionRecord record = getTransaction(transactionId);
        record.setStatus(status);
        return transactionRepository.save(record);
    }
}

