package com.example.enterprise.web;

import com.example.enterprise.domain.TransactionRecord;
import com.example.enterprise.domain.TransactionStatus;
import com.example.enterprise.domain.TransactionType;
import com.example.enterprise.service.TransactionService;
import java.math.BigDecimal;
import java.util.List;
import org.springframework.http.HttpStatus;
import org.springframework.web.bind.annotation.DeleteMapping;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PathVariable;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.PutMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.ResponseStatus;
import org.springframework.web.bind.annotation.RestController;

@RestController
@RequestMapping("/api/transactions")
public class TransactionController {

    private final TransactionService transactionService;

    public TransactionController(TransactionService transactionService) {
        this.transactionService = transactionService;
    }

    public static class CreateTransactionRequest {
        public Long userId;
        public BigDecimal amount;
        public TransactionType type;
        public String description;
    }

    public static class UpdateStatusRequest {
        public TransactionStatus status;
    }

    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    public TransactionRecord create(@RequestBody CreateTransactionRequest request) {
        return transactionService.createTransaction(request.userId, request.amount, request.type, request.description);
    }

    @GetMapping("/{id}")
    public TransactionRecord getById(@PathVariable Long id) {
        return transactionService.getTransaction(id);
    }

    @GetMapping("/user/{userId}")
    public List<TransactionRecord> getByUser(@PathVariable Long userId) {
        return transactionService.getTransactionsByUser(userId);
    }

    @PutMapping("/{id}/status")
    public TransactionRecord updateStatus(@PathVariable Long id, @RequestBody UpdateStatusRequest request) {
        return transactionService.updateStatus(id, request.status);
    }

    @DeleteMapping("/{id}")
    @ResponseStatus(HttpStatus.NO_CONTENT)
    public void delete(@PathVariable Long id) {
        transactionService.updateStatus(id, TransactionStatus.REVERSED);
    }
}

